SELECT e.employeeid, e.firstname, e.lastname, o.orderid, o.orderdate, o.shippeddate, SUM(od.unitprice * od.quantity * (1 - od.discount)) AS order_revenue FROM employees e JOIN orders o ON e.employeeid = o.employeeid JOIN "order details" od ON o.orderid = od.orderid JOIN employeeterritories et ON e.employeeid = et.employeeid JOIN territories t ON et.territoryid = t.territoryid WHERE e.title = 'Sales Representative' AND t.regionid = 1 AND strftime('%Y', o.shippeddate) = '1997' GROUP BY e.employeeid, e.firstname, e.lastname, o.orderid, o.orderdate, o.shippeddate
